1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // === Simplest cases ===
6	  it("empty item list → premium 5 G (only the processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result.results[0]).toEqual({ premium: 5 });
12	  });
13	
14	  // === Base premiums for main items (with processing fee, no other modifiers, no customer history) ===
15	  it("single sword (steel, enchantment 0, not cursed), newcomer's first contract → 100 + 10 first + 5 fee = 115 G", () => {
16	    const result = runScenario({
17	      customer: { yearsWithMHPCO: 0 },
18	      steps: [
19	        {
20	          op: "quote",
21	          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
22	        },
23	      ],
24	    });
25	    expect(result.results[0]).toEqual({ premium: 115 });
26	  });
27	  it("single amulet base premium 60 G applied correctly in newcomer first contract scenario → 60 + 6 first + 5 fee = 71 G", () => {
28	    const result = runScenario({
29	      customer: { yearsWithMHPCO: 0 },
30	      steps: [
31	        { op: "quote", items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }] },
32	      ],
33	    });
34	    expect(result.results[0]).toEqual({ premium: 71 });
35	  });
36	  it("single staff base premium 80 G in newcomer first contract → 80 + 8 first + 5 fee = 93 G", () => {
37	    const result = runScenario({
38	      customer: { yearsWithMHPCO: 0 },
39	      steps: [{ op: "quote", items: [{ type: "staff" }] }],
40	    });
41	    expect(result.results[0]).toEqual({ premium: 93 });
42	  });
43	  it("single potion base premium 40 G in newcomer first contract → 40 + 4 first + 5 fee = 49 G", () => {
44	    const result = runScenario({
45	      customer: { yearsWithMHPCO: 0 },
46	      steps: [{ op: "quote", items: [{ type: "potion" }] }],
47	    });
48	    expect(result.results[0]).toEqual({ premium: 49 });
49	  });
50	
51	  // === Components block-of-3 rule ===
52	  it("2 runes → 50 G base premium (no block); total newcomer premium = 50 + 5 first + 5 fee = 60 G", () => {
53	    const result = runScenario({
54	      customer: { yearsWithMHPCO: 0 },
55	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
56	    });
57	    expect(result.results[0]).toEqual({ premium: 60 });
58	  });
59	  it("3 runes → 60 G base premium (block applies); total premium for newcomer = 60 + 6 + 5 = 71 G", () => {
60	    const result = runScenario({
61	      customer: { yearsWithMHPCO: 0 },
62	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
63	    });
64	    expect(result.results[0]).toEqual({ premium: 71 });
65	  });
66	  it("4 runes → 100 G base premium (no block — block requires exactly 3); total newcomer premium = 115 G", () => {
67	    const result = runScenario({
68	      customer: { yearsWithMHPCO: 0 },
69	      steps: [
70	        {
71	          op: "quote",
72	          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }],
73	        },
74	      ],
75	    });
76	    expect(result.results[0]).toEqual({ premium: 115 });
77	  });
78	  it("7 runes → 175 G base premium (no block possible from 7); total newcomer = 197.5 → 198 G (rounded up)", () => {
79	    const result = runScenario({
80	      customer: { yearsWithMHPCO: 0 },
81	      steps: [
82	        {
83	          op: "quote",
84	          items: Array.from({ length: 7 }, () => ({ type: "rune" })),
85	        },
86	      ],
87	    });
88	    expect(result.results[0]).toEqual({ premium: 198 });
89	  });
90	
91	  // === Alike components clarification ===
92	  it("2 runes + 1 moonstone → 75 G base premium (no block: different types); total newcomer = 88 G", () => {
93	    const result = runScenario({
94	      customer: { yearsWithMHPCO: 0 },
95	      steps: [
96	        {
97	          op: "quote",
98	          items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
99	        },
100	      ],
101	    });
102	    expect(result.results[0]).toEqual({ premium: 88 });
103	  });
104	  it("3 runes + 3 moonstones → 120 G base premium (two separate blocks); total newcomer = 137 G", () => {
105	    const result = runScenario({
106	      customer: { yearsWithMHPCO: 0 },
107	      steps: [
108	        {
109	          op: "quote",
110	          items: [
111	            { type: "rune" }, { type: "rune" }, { type: "rune" },
112	            { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
113	          ],
114	        },
115	      ],
116	    });
117	    expect(result.results[0]).toEqual({ premium: 137 });
118	  });
119	
120	  // === Modifier scope on multi-item policies ===
121	  it.todo("cursed sword + plain amulet for newcomer first contract → 210 G base + first/fee");
122	
123	  // === Modifier thresholds ===
124	  it.todo("customer with exactly 2 years with MHPCO → loyalty discount applies");
125	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
126	  it.todo("sword with exactly enchantment 5 AND cursed → both surcharges apply");
127	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
128	
129	  // === Rounding (in MHPCO's favor — premium rounds up) ===
130	  it.todo("premium calculation yielding 197.5 G → final premium 198 G");
131	
132	  // === Edge case errors for quote ===
133	  it.todo("quote with unknown item type → throws/rejects");
134	
135	  // === Integration examples ===
136	  it.todo("newcomer with a cursed sword (enchantment 3) → premium 165 G");
137	  it.todo("long-standing customer's second contract: cursed sword enchantment 7 → premium 160 G");
138	
139	  // === Claim processing — standard reimbursement ===
140	  it.todo("regular sword damage 500 G → payout 400 G (full minus 100 G deductible)");
141	  it.todo("rune damage 200 G → payout 100 G (full minus 100 G deductible)");
142	
143	  // === Claim — special clauses ===
144	  it.todo("dragon-material sword enchantment 8 damage 1000 G → payout 400 G (high-ench 50% then deductible)");
145	  it.todo("dragon-material sword enchantment 9 damage 1000 G → payout 400 G (50% wins, then deductible)");
146	  it.todo("dragon-material sword enchantment 5 damage 800 G → payout 700 G (full minus deductible)");
147	  it.todo("steel sword enchantment 9 damage 1000 G → payout 400 G (50% then deductible)");
148	
149	  // === Deductible per damage event ===
150	  it.todo("dragon attack damaging sword (500) and amulet (300) → payout 600 G (deductible per item)");
151	
152	  // === Multiple items of the same type ===
153	  it.todo("policy with two swords → insurance sum 2000 G, cap 4000 G; both damaged → separate deductibles");
154	  it.todo("damages array contains more entries of a type than insured → claim rejected (non-zero exit)");
155	
156	  // === Cap exhaustion ===
157	  it.todo("sword + amulet → insurance sum 1600 G, cap 3200 G");
158	  it.todo("cursed sword → cap 2000 G (based on unmodified insurance value)");
159	  it.todo("sword + 3 runes → insurance sum 1750 G (block discount does not affect insurance sum)");
160	  it.todo("sword cap 2000 G, two successive 1500 G claims → first payout 1400 G (cap 600), second payout 600 G (cap 0)");
161	
162	  // === Payout rounding (in MHPCO's favor — payout rounds down) ===
163	  it.todo("payout calculation yielding 350.5 G → final payout 350 G");
164	
165	  // === Claim error cases ===
166	  it.todo("claim references damage entry for item not in policy → rejected");
167	  it.todo("claim contains damage entry with negative amount → rejected");
168	});
